const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text;
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json;
return [{ json: { data: data, topic: r.topic, date: r.date, client: r.client, markdown: raw } }];

/* --- Jarvis brand kit (shared across awareness PDFs): avatar + takeaways box + sign-off --- */
var __jfs=null; try{__jfs=require('fs');}catch(e){}
function jAvatarUri(){ if(!__jfs) return ''; var t=[['/config/branding/jarvis-avatar.png','image/png'],['/config/branding/jarvis-avatar.jpg','image/jpeg'],['/config/branding/jarvis-avatar.jpeg','image/jpeg'],['/config/branding/jarvis-avatar.svg','image/svg+xml']]; for(var i=0;i<t.length;i++){ try{ return 'data:'+t[i][1]+';base64,'+__jfs.readFileSync(t[i][0]).toString('base64'); }catch(e){} } return ''; }
var JKIT_SVG='<svg class="jav" viewBox="0 0 64 64" xmlns="http://www.w3.org/2000/svg"><defs><linearGradient id="jkitg" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#0E7C86"/><stop offset="1" stop-color="#0A1A2F"/></linearGradient></defs><circle cx="32" cy="32" r="32" fill="url(#jkitg)"/><rect x="19" y="21" width="26" height="22" rx="7" fill="#fff"/><circle cx="27" cy="32" r="3.2" fill="#0E7C86"/><circle cx="37" cy="32" r="3.2" fill="#0E7C86"/><rect x="27" y="38" width="10" height="2.4" rx="1.2" fill="#0E7C86"/><rect x="30.7" y="14" width="2.6" height="6" rx="1.3" fill="#9fe4d8"/><circle cx="32" cy="13" r="2.4" fill="#E7C76A"/><path d="M23 47h18l-3 4.5H26z" fill="#9fe4d8"/></svg>';
var JKIT_CSS=".jkit-take{background:#F4F6F9;border:1px solid #E2E6EC;border-left:4px solid #0E7C86;border-radius:10px;padding:14px 18px;margin:22px 0 0;page-break-inside:avoid}.jkit-take .th{font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:11px;letter-spacing:2px;text-transform:uppercase;color:#0A1A2F;font-weight:800;margin:0 0 7px}.jkit-take ul{margin:0;padding-left:18px}.jkit-take li{font-size:13.5px;line-height:1.5;color:#2b3340;margin:5px 0}.jkit-sign{display:flex;align-items:center;gap:12px;margin:20px 0 0;padding-top:14px;border-top:2px solid #0E7C86;page-break-inside:avoid}.jkit-sign img,.jkit-sign .jav{width:46px;height:46px;border-radius:50%;border:2px solid #0E7C86;flex:0 0 auto}.jkit-sign .nm{font-family:Georgia,serif;font-size:15px;color:#0A1A2F;font-weight:700}.jkit-sign .rl{font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:10px;letter-spacing:2px;text-transform:uppercase;color:#0E7C86;font-weight:800;margin-top:2px}";
function jKitEsc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function jTakeBox(takeaways){ var t=(takeaways||[]).filter(Boolean).slice(0,4); if(!t.length) return ''; return '<div class="jkit-take"><div class="th">Key takeaways &middot; Lessons learned</div><ul>'+t.map(function(x){return '<li>'+jKitEsc(x)+'</li>';}).join('')+'</ul></div>'; }
function jSignoff(){ var av=jAvatarUri(); var avatar=av?('<img src="'+av+'"/>'):JKIT_SVG; return '<div class="jkit-sign">'+avatar+'<div><div class="nm">Jarvis</div><div class="rl">Your AI Awareness Assistant</div></div></div>'; }
function jKitBlock(takeaways){ return jTakeBox(takeaways)+jSignoff(); }

const d=$json.data||{}; const topic=$json.topic||'Security'; const date=$json.date||''; const client=($json.client||'').toString();
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
const byline=client?('Prepared for '+client):'Security Awareness';
var tipsHtml=((d.tips||[]).map(function(t){return '<div class="tip"><div class="th">'+esc(t.title)+'</div><div class="td">'+esc(t.tip)+'</div></div>';}).join(''));
var cards=((d.cards||[]).map(function(c){return '<div class="lock"><div class="lk">SECURITY TIP</div><div class="lf">'+esc(c.front)+'</div><div class="lb">'+esc(c.back)+'</div><div class="lfoot">'+esc(byline)+'</div></div>';}).join(''));
var EXTRA=" .tip{border-left:4px solid #0E7C86;background:#F4F8F8;border-radius:6px;padding:10px 14px;margin:9px 0;page-break-inside:avoid} .th{font-weight:800;color:#0E2233;font-size:14px} .td{font-size:13px;color:#2b3340;margin-top:3px} .lock{height:100vh;page-break-before:always;background:linear-gradient(150deg,#0E2233,#0E7C86);color:#fff;position:relative;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:60px} .lock .lk{position:absolute;top:48px;letter-spacing:4px;font-size:13px;color:#9fe4d8;font-weight:800} .lock .lf{font-size:46px;font-weight:800;line-height:1.1;max-width:80%} .lock .lb{font-size:20px;color:#CDE7F0;margin-top:18px;max-width:70%} .lock .lfoot{position:absolute;bottom:48px;color:#8fb3c2;font-size:13px;letter-spacing:1px}";
var CSS="@page{size:A4;margin:16mm 15mm 18mm} *{box-sizing:border-box} body{margin:0;font-family:-apple-system,\"Segoe UI\",Arial,sans-serif;color:#11151c} .pg{page-break-after:always} .pg:last-child{page-break-after:auto} .kick{color:#0E7C86;letter-spacing:2px;font-weight:800;font-size:12px;text-transform:uppercase} h1.t{font-family:Georgia,serif;font-size:30px;color:#0E2233;margin:6px 0 4px} .sub{color:#5A6472;font-size:13px;margin:0 0 18px} h2{font-family:Georgia,serif;font-size:19px;color:#0E2233;margin:20px 0 10px;border-bottom:2px solid #0E7C86;padding-bottom:6px} p{font-size:14px;line-height:1.6;color:#2b3340} .foot{position:fixed;bottom:8mm;left:15mm;right:15mm;color:#9aa6b2;font-size:11px;border-top:1px solid #E2E6EC;padding-top:8px;display:flex;justify-content:space-between} .card{border:1px solid #E2E6EC;border-radius:8px;padding:14px 16px;margin:12px 0;page-break-inside:avoid} .card h3{margin:0 0 8px;font-family:Georgia,serif;font-size:16px;color:#0E2233} .pill{display:inline-block;background:#E6F4F1;color:#0E7C86;font-weight:800;font-size:11px;padding:3px 10px;border-radius:12px;letter-spacing:.5px}"+EXTRA+JKIT_CSS;
var page1='<div class="pg"><div class="kick">Security Tips</div><h1 class="t">'+esc(topic)+' — Tips</h1><div class="sub">'+esc(d.intro||'Small habits, big protection.')+'</div>'+tipsHtml+jKitBlock(d.takeaways)+'<div class="foot"><span>'+esc(byline)+'</span><span>'+esc(date)+'</span></div></div>';
const html='<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body>'+page1+cards+'</body></html>';
const fileSafe=topic.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,40)||'tips';
return [{ json:{ html:html, topic:topic, date:date, fileSafe:fileSafe, outDir:'tips', filePrefix:'tips' } }];

const html = $json.html || '';
return [{ json: { topic:$json.topic, date:$json.date, fileSafe:$json.fileSafe, outDir:$json.outDir, filePrefix:$json.filePrefix },
  binary: { data: { data: Buffer.from(html,'utf8').toString('base64'), mimeType:'text/html', fileName:'index.html' } } }];

const fs = require('fs');
const meta = $('Render HTML').first().json;
const dir = '/reports/awareness/' + (meta.outDir || 'misc');
const name = (meta.filePrefix || 'asset') + '-' + (meta.fileSafe || 'item') + '-' + meta.date + '.pdf';
let buf = null;
try { buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (e) {}
try { fs.mkdirSync(dir, { recursive: true }); if (buf) fs.writeFileSync(dir + '/' + name, buf); } catch (e) {}
const out = { json: { ok: !!buf, file: dir + '/' + name, topic: meta.topic } };
try { const b = $input.first().binary; if (b && b.data) { b.data.fileName = name; out.binary = { data: b.data }; } } catch (e) {}
return [out];
